// Helper: recursively search for a key containing the LLM JSON string
function findResponse(obj) {
  if (!obj || typeof obj !== "object") return null;

  // direct hit: key named "response"
  if (typeof obj.response === "string") return obj.response;

  // OAI-style result: choices[0].message.content
  if (obj.choices && obj.choices[0]?.message?.content) {
    return obj.choices[0].message.content;
  }

  // Try any string-like field that looks like JSON
  for (const key of Object.keys(obj)) {
    const val = obj[key];
    if (typeof val === "string" && val.trim().startsWith("{")) return val;
    if (typeof val === "string" && val.trim().startsWith("[")) return val;

    // recursively search children
    if (typeof val === "object") {
      const inner = findResponse(val);
      if (inner) return inner;
    }
  }

  return null;
}

// STEP 1: Get the entire incoming JSON from the LLM node
const llmNode = $node["LLM Node"];   // ← change name if needed
const incoming = llmNode.json;

// STEP 2: Extract the JSON string safely
const llmRaw = findResponse(incoming);

if (!llmRaw) {
  throw new Error(
    "Could not locate LLM response text. Inspect incoming data from LLM node."
  );
}

// STEP 3: Parse the JSON
let llm;
try {
  llm = JSON.parse(llmRaw);
} catch (e) {
  throw new Error("LLM returned invalid JSON: " + e.message + " — Raw: " + llmRaw);
}

// STEP 4: Extract values
const num = parseInt(llm.num_sprints || 3, 10);

// Format cleaner
function clean(n) {
  return (n || "")
    .toString()
    .replace(/[\r\n\t]+/g, " ")
    .replace(/\s{2,}/g, " ")
    .trim();
}

// STEP 5: Build Trello lists
const lists = [];
lists.push({ json: { name: "Backlog" } });

for (let i = 1; i <= num; i++) {
  lists.push({ json: { name: clean(`Sprint ${i}`) } });
}

return lists;

