// 1) Build availableLists from incoming Trello Create List outputs
const itemsIn = $input.all();
const availableLists = {};
itemsIn.forEach(it => {
  const list = it.json;
  if (list && list.name && list.id) {
    const key = list.name.toString().toLowerCase().replace(/\s+/g, '');
    availableLists[key] = list.id;
  }
});
console.log('availableLists keys:', Object.keys(availableLists));

// 2) Helper: try to find the ParseLLM node (allow several common names)
function getParseNode() {
  const candidates = ["ParseLLM", "LLM Parse", "Parse LLM", "parseLLM", "parseLlm"];
  for (const name of candidates) {
    try {
      const n = $node[name];
      if (n) return n;
    } catch(e) {}
  }
  // fallback try exact known
  try { return $node["ParseLLM"]; } catch(e){}
  return null;
}

// 3) Extract stories array safely
let parseNode = getParseNode();
let stories = [];

if (!parseNode) {
  console.warn("ParseLLM node not found. Make sure the node name is correct.");
} else {
  const pj = parseNode.json;
  // pj may be an array or an object
  let data = pj;
  if (Array.isArray(pj) && pj.length) data = pj[0];

  // case A: already parsed shape { project_title, stories: [...] }
  if (data && Array.isArray(data.stories)) {
    stories = data.stories;
  } else if (data && typeof data.response === "string") {
    // case B: response is a JSON string -> parse
    try {
      const parsed = JSON.parse(data.response);
      if (parsed && Array.isArray(parsed.stories)) stories = parsed.stories;
      else if (parsed && Array.isArray(parsed)) stories = parsed; // in case it's raw array
    } catch (e) {
      console.warn("Could not JSON.parse(parseNode.json.response):", e.message);
    }
  } else if (data && typeof data === "object") {
    // fallback: try to find a property that is an array of stories
    for (const k of Object.keys(data)) {
      if (Array.isArray(data[k]) && data[k].length && data[k][0].id) {
        stories = data[k];
        break;
      }
      if (Array.isArray(data[k]) && data[k].length && typeof data[k][0] === 'object') {
        // last resort take first array
        stories = data[k];
        break;
      }
    }
  }
}

console.log("Extracted stories count:", stories.length);

// 4) Map stories to Trello lists
const mapped = stories.map(story => {
  // ensure story exists and has id
  const sid = story && story.id ? story.id : null;

  // determine desired list key: sprintN or backlog
  let listKey;
  if (typeof story?.sprint === "number" && !Number.isNaN(story.sprint)) {
    listKey = `sprint${story.sprint}`;
  } else {
    listKey = 'backlog';
  }
  const cleanKey = listKey.toLowerCase().replace(/\s+/g, '');

  // choose list id (fallback to backlog id or null)
  const listId = availableLists[cleanKey] || availableLists['backlog'] || null;
  if (!listId) console.warn(`No Trello list id found for key '${cleanKey}' (story ${sid})`);

  // return item for downstream Trello create-card or other nodes
  return {
    json: {
      ...story,
      listId
    }
  };
});

// 5) Always return an array (could be empty, but not undefined)
console.log("Mapped stories ready:", mapped.length);
return mapped;

