// Get all input stories
const items = $input.all();

// Map stories to Trello card data
return items.map((item, index) => {
  const story = item.json;

  // Compute due date: estimate days from now, fixed time 12:00 UTC
  const dueDate = new Date();
  dueDate.setDate(dueDate.getDate() + (story.estimate || 3));
  const dueDateFormatted = dueDate.toISOString().split('T')[0] + 'T12:00:00.000Z';

  // Build description without duplicating acceptance criteria
  const description = [
    `Role: ${story.role}`,
    `Goal: ${story.goal}`,
    `Benefit: ${story.benefit}`,
    `Estimate: ${story.estimate} days`,
    `Priority: ${story.priority}`,
    `Tags: ${story.tags && story.tags.length ? story.tags.join(', ') : 'None'}`,
    `Dependencies: ${story.dependencies && story.dependencies.length ? story.dependencies.join(', ') : 'None'}`
  ].join('\n');

  return {
    json: {
      // Trello card fields
      idList: story.listId || (story.availableLists ? story.availableLists.backlog : null),
      name: `${story.id}: ${story.title}`,
      desc: description,
      due: dueDateFormatted,
      pos: index + 1, // maintain order

      // Preserve full story data including acceptance criteria
      originalStory: {
        project_title: story.project_title,
        id: story.id,
        title: story.title,
        role: story.role,
        goal: story.goal,
        benefit: story.benefit,
        acceptance_criteria: story.acceptance_criteria || [],
        priority: story.priority,
        estimate: story.estimate,
        dependencies: story.dependencies || [],
        assignee: story.assignee || "",
        tags: story.tags || [],
        sprint: story.sprint || null,
        listId: story.listId || null
      }
    }
  };
});

const items = $input.all();

return items.flatMap(item => {
  const mergedData = item.json;
  const cardId = mergedData.id;
  const acceptanceCriteria = mergedData.originalStory?.acceptance_criteria || [];

  console.log(`Creating checklist for card: ${cardId}`);

  if (acceptanceCriteria.length === 0) return [];

  // Create requests: first the checklist, then all items
  const requests = [];

  // 1. Checklist creation request
  requests.push({
