const createdCards = $input.all(); // Output from HTTP Create Cards
const originalData = $('formatCardData').all(); // Output from your format function

console.log('Created cards count:', createdCards.length);
console.log('Original data count:', originalData.length);

// Merge the Trello response with our original data
const mergedData = createdCards.map((cardItem, index) => {
