const items = $input.all();

// We need to get data from TWO previous nodes:
// - HTTP Create Checklist output (checklist IDs)
// - Function CreateChecklistWithData output (acceptance criteria)
$('Checklist Request').first().json.method
const checklistResponses = items;
const originalRequests = $('Checklist Request').all();

console.log('Checklist responses:', checklistResponses.length);
console.log('Original requests:', originalRequests.length);

const results = [];

checklistResponses.forEach((checklistItem, index) => {
  const checklistResponse = checklistItem.json;
  const checklistId = checklistResponse.id;

  // Find the matching original request to get acceptance criteria
  const originalRequest = originalRequests[index];
  const acceptanceCriteria = originalRequest?.json?._acceptanceCriteria || [];

  console.log(`Checklist ${checklistId} has ${acceptanceCriteria.length} items to add`);

  if (acceptanceCriteria.length === 0) return;

  // Create a request for each acceptance criteria
  acceptanceCriteria.forEach((criteria, itemIndex) => {
    results.push({
      json: {
        method: 'POST',
        url: `https://api.trello.com/1/checklists/${checklistId}/checkItems`,
        query: {
          name: criteria,
          pos: itemIndex
        }
      }
    });
  });
});

return results;

