// Robust reader (handles webhook shape you showed)
function readRawFromItem(item) {
  if (!item || !item.json) return "";
  // preferred explicit field(s)
  if (typeof item.json.userStories === 'string') return item.json.userStories;
  if (item.json.body && typeof item.json.body.userStories === 'string') return item.json.body.userStories;
  if (typeof item.json.stories_text === 'string') return item.json.stories_text;
  if (typeof item.json.body === 'string') return item.json.body;
  if (typeof item.json.rawBody === 'string') return item.json.rawBody;

  // if whole json is a single string value
  const keys = Object.keys(item.json || {});
  if (keys.length === 1 && typeof item.json[keys[0]] === 'string') {
    return item.json[keys[0]];
  }

  // binary fallback
  if (item.binary) {
    const bkeys = Object.keys(item.binary);
    if (bkeys.length) {
      const bin = item.binary[bkeys[0]];
      if (bin && bin.data) {
        return Buffer.from(bin.data, 'base64').toString('utf8');
      }
    }
  }

  try {
    return JSON.stringify(item.json);
  } catch (e) {
    return "";
  }
}

// --- Get raw stories from the first input item ---
const item = items[0]; // n8n Function node uses `items`
const rawStories = (readRawFromItem(item) || "").trim();

if (!rawStories) {
  throw new Error("No user stories found in incoming item. Look for body.userStories or stories_text in the previous node output.");
}

// --- Optional: normalize into an array if you want (not required for prompt) ---
function toArrayIfMultiline(text) {
  // If it's a single long string with multiple US- entries keep it as-is for prompt.
  // But we also produce a short list for debug/summary if needed.
  const lines = text.split(/\r?\n/).map(s => s.trim()).filter(Boolean);
  // heuristics: group lines starting with *US- or "As a" -> keep as raw
  return lines;
}
const storyLines = toArrayIfMultiline(rawStories);

// --- Build the prompt (ensures rawStories are included) ---
const prompt = `You are an expert Scrum Master AI and JSON extractor.

Requirements:
- Create a "project_title" inferred from the user stories.
- Decide an appropriate "sprint_capacity" (number) and "num_sprints" between 3 and 5.
- Extract each user story into objects with EXACT fields:
  id, project_title, title, role, goal, benefit,
  acceptance_criteria (array of strings), priority (Low|Medium|High),
  estimate (number), dependencies (array), assignee (string),
  tags (array), sprint.

Rules:
- Tags: if story contains design/mock/style/palette/mockup -> add "design"
- If story mentions branch/PR/git/screenshot/push -> add "dev"
- If story mentions migration/database/users/created_at/email/is_active/id -> add "backend"
- If story mentions test_user_ or acceptance test -> add "qa" and "tests"
- Priority -> High if urgent/blocker/ASAP, otherwise Medium
- Estimate -> 2 if <=1 AC, 3 if 2 ACs, 5 if 3+ ACs
- num_sprints must be an integer between 3 and 5 inclusive

IMPORTANT:
- RETURN ONLY valid JSON (no markdown, no explanation).
- Top-level response must be an object with keys:
  { "project_title": "...", "sprint_capacity": <number>, "num_sprints": <3-5>, "stories": [ ... ] }

Now extract from the raw user stories below. Preserve all original text for context.

RAW USER STORIES:
${rawStories}

Return JSON only.`;


// --- Build body object you'll POST to Ollama (ready to stringify) ---
const bodyForOllama = {
  model: "gpt-oss:120b",    // change to your desired cloud model
  prompt: prompt,
  format: "json",
  stream: false
};

// Return both prompt and bodyForOllama
return [
  {
    json: {
      prompt,
      bodyForOllama,
      _debug_preview_lines: storyLines.slice(0,10) // small debug preview (optional)
    }
  }
];

// Simple Parse LLM output (Function node)
// Make sure the LLM node name below matches your workflow: "LLM Node"

function stripFences(s) {
  if (!s) return s;
  s = s.trim();
  // remove ```json ... ``` or ``` ... ```
  if (s.startsWith("```")) {
    s = s.replace(/^```(?:json)?\s*/, "").replace(/\s*```$/, "");
  }
  return s;
}

let raw = null;

// try common locations on the LLM node
try {
  const nn = $node["LLM Node"]; // <-- change name here if your node is named differently
  if (nn) {
    const j = nn.json;
    // nn.json may be an array or object
    if (Array.isArray(j) && j.length) {
      raw = j[0].response || j[0].text || j[0].output || null;
    } else if (j && typeof j === "object") {
      raw = j.response || j.text || j.output || null;
    }
  }
} catch (e) {
  // ignore, try fallback below
}

// fallback: maybe the Function node itself received the LLM item as input
if (!raw && items && items[0] && items[0].json) {
  raw = items[0].json.response || items[0].json.text || null;
}

if (!raw) {
  // always return an item so downstream doesn't break
  return [{ json: { error: "LLM response not found - check node name and incoming data" } }];
}

// strip fences then parse
const cleaned = stripFences(raw);

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  return [{
    json: {
      error: "Failed to parse LLM JSON",
      message: err.message,
      rawPreview: cleaned.slice(0, 1000) // small preview for debugging
    }
  }];
}

// normalize output and return single item with structured data
const out = {
  project_title: parsed.project_title || null,
  sprint_capacity: parsed.sprint_capacity || null,
  num_sprints: parsed.num_sprints || null,
  stories: Array.isArray(parsed.stories) ? parsed.stories : []
};

return [{ json: out }];
